import React, { Component } from "react";
import $ from "jquery";
import "./App.scss";
import Header from "./components/Header";
import Footer from "./components/Footer";
import About from "./components/About";
import Experience from "./components/Experience";
import Projects from "./components/Projects";
import Skills from "./components/Skills";
import { motion } from "framer-motion"; // Import motion

class App extends Component {
  constructor(props) {
    super();
    this.state = {
      foo: "bar",
      resumeData: {},
      sharedData: {},
      activeLanguage: window.$primaryLanguage // Track active language for animation
    };
  }

  applyPickedLanguage(pickedLanguage, oppositeLangIconId) {
    this.setState({ activeLanguage: pickedLanguage }); // Update state
    this.swapCurrentlyActiveLanguage(oppositeLangIconId);
    document.documentElement.lang = pickedLanguage;
    var resumePath =
      document.documentElement.lang === window.$primaryLanguage
        ? `res_primaryLanguage.json`
        : `res_secondaryLanguage.json`;
    this.loadResumeFromPath(resumePath);
  }

  swapCurrentlyActiveLanguage(oppositeLangIconId) {
    var pickedLangIconId =
      oppositeLangIconId === window.$primaryLanguageIconId
        ? window.$secondaryLanguageIconId
        : window.$primaryLanguageIconId;
    document
      .getElementById(oppositeLangIconId)
      .removeAttribute("filter", "brightness(40%)");
    document
      .getElementById(pickedLangIconId)
      .setAttribute("filter", "brightness(40%)");
  }

  componentDidMount() {
    this.loadSharedData();
    this.applyPickedLanguage(
      window.$primaryLanguage,
      window.$secondaryLanguageIconId
    );
  }

  loadResumeFromPath(path) {
    $.ajax({
      url: path,
      dataType: "json",
      cache: false,
      success: function (data) {
        this.setState({ resumeData: data });
      }.bind(this),
      error: function (xhr, status, err) {
        alert(err);
      },
    });
  }

  loadSharedData() {
    $.ajax({
      url: `portfolio_shared_data.json`,
      dataType: "json",
      cache: false,
      success: function (data) {
        this.setState({ sharedData: data });
        document.title = data.basic_info.name;
      }.bind(this),
      error: function (xhr, status, err) {
        alert(err);
      },
    });
  }

  render() {
    return (
      <div>
        <Header sharedData={this.state.sharedData.basic_info} />

        {/* Animated Language Switcher */}
        <div className="col-md-12 mx-auto text-center language" style={{ marginTop: '20px', marginBottom: '20px' }}>

          {/* Primary Language (UK Flag) */}
          <motion.div
            onClick={() =>
              this.applyPickedLanguage(
                window.$primaryLanguage,
                window.$secondaryLanguageIconId
              )
            }
            style={{ 
              display: "inline-block", 
              cursor: 'pointer', 
              marginRight: '30px',
              padding: '5px' 
            }}
            whileHover={{ scale: 1.2 }}
            whileTap={{ scale: 0.9 }}
            animate={{ 
              opacity: this.state.activeLanguage === window.$primaryLanguage ? 1 : 0.5,
              borderBottom: this.state.activeLanguage === window.$primaryLanguage ? '2px solid #AE944F' : '2px solid transparent'
            }}
          >
            <span
              className="iconify language-icon"
              data-icon="twemoji-flag-for-flag-united-kingdom"
              data-inline="false"
              id={window.$primaryLanguageIconId}
              style={{ fontSize: '35px' }}
            ></span>
          </motion.div>

          {/* Secondary Language (India Flag) */}
          <motion.div
            onClick={() =>
              this.applyPickedLanguage(
                window.$secondaryLanguage,
                window.$primaryLanguageIconId
              )
            }
            style={{ 
              display: "inline-block", 
              cursor: 'pointer',
              padding: '5px' 
            }}
            whileHover={{ scale: 1.2 }}
            whileTap={{ scale: 0.9 }}
            animate={{ 
              opacity: this.state.activeLanguage === window.$secondaryLanguage ? 1 : 0.5,
              borderBottom: this.state.activeLanguage === window.$secondaryLanguage ? '2px solid #AE944F' : '2px solid transparent'
            }}
          >
            <span
              className="iconify language-icon"
              data-icon="twemoji-flag-for-flag-india"
              data-inline="false"
              id={window.$secondaryLanguageIconId}
              style={{ fontSize: '35px' }}
            ></span>
          </motion.div>
        </div>

        <About
          resumeBasicInfo={this.state.resumeData.basic_info}
          sharedBasicInfo={this.state.sharedData.basic_info}
        />
        <Projects
          resumeProjects={this.state.resumeData.projects}
          resumeBasicInfo={this.state.resumeData.basic_info}
        />
        <Skills
          sharedSkills={this.state.sharedData.skills}
          resumeBasicInfo={this.state.resumeData.basic_info}
        />
        <Experience
          resumeExperience={this.state.resumeData.experience}
          resumeBasicInfo={this.state.resumeData.basic_info}
        />
        <Footer sharedBasicInfo={this.state.sharedData.basic_info} />
      </div>
    );
  }
}

export default App;
